#!/usr/bin/env node
/**
 * Pre-publish CSS bundler.
 *
 * The preset's src/css/tokens.css normally imports the design-system
 * monorepo's canonical tokens.css and typography.css via three-up
 * relative paths (`@import url("../../../tokens.css")` etc.). Those
 * paths only resolve inside the monorepo. When the package is installed
 * from npm into a consumer site, the imports resolve to nothing and
 * webpack fails the build with `Can't resolve '../../../tokens.css'`.
 *
 * This script runs as the preset's `prepack` lifecycle, which npm fires
 * before `npm publish` (and before `npm pack`). It inlines the canonical
 * token + typography content into src/css/tokens.css so the published
 * tarball is self-contained. Local dev is unaffected because we don't
 * pack/publish locally — the working-tree copy keeps the relative
 * imports and stays in sync with the monorepo's single source of truth
 * via the @import.
 *
 * The check at the bottom guards against CI failures that ship an empty
 * or noticeably-truncated bundle; the working tokens.css is ~437 lines.
 */
const fs = require('node:fs');
const path = require('node:path');

const presetRoot = path.resolve(__dirname, '..');
const monorepoRoot = path.resolve(presetRoot, '..');

const tokensSrc = path.join(monorepoRoot, 'tokens.css');
const typographySrc = path.join(monorepoRoot, 'typography.css');
const out = path.join(presetRoot, 'src', 'css', 'tokens.css');

const tokens = fs.readFileSync(tokensSrc, 'utf8');
const typography = fs.readFileSync(typographySrc, 'utf8');

const header = `/* AUTO-GENERATED by docusaurus-preset/scripts/prepack-bundle-css.js
 * during \`npm publish\`. Bundles the design-system monorepo's canonical
 * tokens.css + typography.css into a self-contained file so consumer
 * sites can resolve the imports through node_modules.
 *
 * Do NOT edit this file in a published version. The working-tree
 * src/css/tokens.css keeps the relative-import version that points
 * back at the monorepo's source of truth.
 */
`;

fs.writeFileSync(out, header + '\n' + tokens + '\n' + typography);

const written = fs.readFileSync(out, 'utf8');
if (written.length < 1000) {
  throw new Error(
    `[prepack-bundle-css] bundled output is only ${written.length} bytes; ` +
      `expected several KB. Refusing to publish a truncated tokens.css.`
  );
}

console.log(
  `[prepack] bundled ${path.basename(tokensSrc)} + ${path.basename(typographySrc)} ` +
    `(${written.length} bytes) -> ${path.relative(presetRoot, out)}`
);
